import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { useId } from 'react';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface MatchData {
  match: {
    homeTeam: string;
    awayTeam: string;
    currentScore: {
      home: number;
      away: number;
    };
    period: string;
    timeRemaining: string;
  };
  keyStats: {
    topScorer: {
      player: string;
      points: number;
    };
    rebounds: {
      home: number;
      away: number;
    };
    assists: {
      home: number;
      away: number;
    };
  };
}

export default function Widget() {
  const data = response.data as MatchData;
  const { match, keyStats } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#212121' }} elevation={3}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              {match.homeTeam} vs {match.awayTeam}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mt: 0.5 }}>
              {match.period} - {match.timeRemaining} remaining
            </Typography>
            <Typography variant="h4" sx={{ color: '#FFFFFF', mt: 1 }}>
              {match.currentScore.home} - {match.currentScore.away}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#424242' }} />

          <Stack direction="row" spacing={1} justifyContent="space-between">
            <Chip label={`Top Scorer: ${keyStats.topScorer.player} (${keyStats.topScorer.points} pts)`} sx={{ bgcolor: '#FFC107', color: '#212121', fontSize: '10px' }} />
            <Chip label={`Rebounds: ${keyStats.rebounds.home} - ${keyStats.rebounds.away}`} sx={{ bgcolor: '#03A9F4', color: '#212121', fontSize: '10px' }} />
            <Chip label={`Assists: ${keyStats.assists.home} - ${keyStats.assists.away}`} sx={{ bgcolor: '#03A9F4', color: '#212121', fontSize: '10px' }} />
          </Stack>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: [keyStats.rebounds.home, keyStats.rebounds.away],
                  color: '#FFC107',
                  label: 'Rebounds',
                },
                {
                  type: 'bar',
                  data: [keyStats.assists.home, keyStats.assists.away],
                  color: '#03A9F4',
                  label: 'Assists',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: [match.homeTeam, match.awayTeam],
                  id: 'teams',
                },
              ]}
              yAxis={[{ id: 'stats' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis axisId="teams" tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }} />
              <ChartsYAxis axisId="stats" tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }} />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
